from __future__ import annotations

import base64
from pathlib import Path

FILES = {'scripts/build_phase_3_parcel_permission.py': '', 'scripts/load_parcel_boundaries_geojson.py': '', 'scripts/load_protection_buffers_geojson.py': '', 'scripts/load_field_names_geojson.py': '', 'scripts/export_permission_candidate.py': ''}

def main() -> None:
    root = Path.cwd()
    for rel_path, encoded in FILES.items():
        target = root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_bytes(base64.b64decode(encoded))
        print(f"[OK] wrote {target}")
    print("[DONE] phase 3 parcel / permission installer applied")
    print("Run next:")
    print("  python scripts/build_phase_3_parcel_permission.py")
    print("Optional loaders:")
    print("  python scripts/load_parcel_boundaries_geojson.py <path-to-geojson>")
    print("  python scripts/load_protection_buffers_geojson.py <path-to-geojson>")
    print("  python scripts/load_field_names_geojson.py <path-to-geojson>")
    print("Permission export:")
    print("  python scripts/export_permission_candidate.py <layer_key> <source_id> <description>")

if __name__ == "__main__":
    main()
